import{c as t,Q as a,j as r,m as i}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"How do I rerun a failed migration?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/rerun-migration.md","filePath":"guide/recipes/admin/rerun-migration.md","lastUpdated":1779094756000}'),o={name:"guide/recipes/admin/rerun-migration.md"};function n(s,e,l,d,c,h){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="how-do-i-rerun-a-failed-migration" tabindex="-1">How do I rerun a failed migration? <a class="header-anchor" href="#how-do-i-rerun-a-failed-migration" aria-label="Permalink to &quot;How do I rerun a failed migration?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong>, <strong>Infra Ops</strong>, or <strong>QA Admin</strong> (within scope)</p></div><p>Rerunning resumes only the tenants that failed in the previous attempt — successful tenants are left alone. The rerun is linked to the original job so the lineage stays intact.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Migrations</strong> and find the failed job (filter by <strong>Status: Failed</strong>).</li><li>Click the row to open the drawer.</li><li>In the drawer header, click <strong>Rerun</strong>.</li><li>The rerun dialog shows which tenants will be retried (the failed ones). Confirm.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>A new job appears with the same root job ID and an incremented <strong>attempt</strong> number. The job drawer shows the lineage — original attempt + every rerun — so you can compare logs across attempts.</p><div class="tip custom-block"><p class="custom-block-title">For instance-replace</p><p>The rerun is <em>resume-failed-only</em> — it picks up exactly where the previous attempt stopped using the <code>instance_replace_results</code> artifact. Tenants that succeeded the first time are not re-imported.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./rollback-migration">How do I roll back a migration?</a></li><li><a href="./start-migration">How do I start a migration?</a></li></ul>',10)])])}const m=t(o,[["render",n]]);export{u as __pageData,m as default};
